module twocounter(in0, in1, out);
  input [7:0] in0;
  input [7:0] in1;
  output  [7:0] out;
  wire signed [15:0] mult_tmp;
  wire signed [7:0] in1;
  wire signed [7:0] in0;
  assign mult_tmp = $signed({1'b0, in0}) * in1;      // Error code，  in1  is  signed variable， so  this operator should be  signed multiplication

  assign out= mult_tmp[7:0];
endmodule

```

